rules.pseudocode:
for each cell s in grid:
    if s has food visible in perception:
        b[s] = b[s] + alpha_b * (1.0 - b[s])
    elif s is visible but has no food:
        b[s] = b[s] + alpha_b * (0.0 - b[s])
    else:  # unobserved
        b[s] = (1 - belief_decay) * b[s]

if agent ate at s_t and received reward r_t:
    phi[s_t] = phi[s_t] + alpha_phi * (r_t - phi[s_t])
else:
    # No update for non-visited cells this step

for each cell s:
    dist = abs(s[0] - x) + abs(s[1] - y)  # Manhattan distance
    A[s] = sigma[s] * (tau ** dist)
